/**
 * CDFI Fund tract eligibility data lookup.
 * The bundled JSON (public/cdfi-tracts.json) is keyed by census tract GEOID.
 *
 * Each record contains (column names normalized to snake_case):
 *   geoid, tract_name, state, county,
 *   poverty_rate, poverty_eligible,
 *   mfi_ratio, income_eligible,
 *   unemployment_rate, unemployment_eligible,
 *   eligible (overall LIC determination)
 *
 * The data file is generated by scripts/process-cdfi-data.mjs
 */

let tractData = null;
let loadError = null;
let loadPromise = null;

async function loadTractData() {
  if (tractData) return tractData;
  if (loadError) throw loadError;
  if (loadPromise) return loadPromise;

  loadPromise = fetch("/cdfi-tracts.json")
    .then(r => {
      if (!r.ok) throw new Error(`Failed to load CDFI tract data: HTTP ${r.status}`);
      return r.json();
    })
    .then(data => {
      tractData = data;
      return data;
    })
    .catch(e => {
      loadError = e;
      throw e;
    });

  return loadPromise;
}

// Synchronous lookup — call after preload
export function lookupTract(geoid) {
  if (!tractData) return null;
  return tractData[geoid] ?? tractData[String(geoid).padStart(11, "0")] ?? null;
}

// Call this at app startup to preload the data
export async function preloadTractData() {
  return loadTractData();
}

export function isTractDataLoaded() {
  return tractData !== null;
}
